public class Proxy {
    interface Service { String fetch(); }
    static class RealService implements Service {
        public String fetch() { return "data"; }
    }
    static class LoggingProxy implements Service {
        private final Service target;
        LoggingProxy(Service s) { target = s; }
        public String fetch() {
            System.out.println("before");
            String r = target.fetch();
            System.out.println("after");
            return r;
        }
    }
    public static void main(String[] args) {
        Service s = new LoggingProxy(new RealService());
        System.out.println(s.fetch());
    }
}
